import Cards from "./Cards";
import { useDrop } from "react-dnd";
import "./ListMaping.css";

export default function ListMaping({
  status,
  toDoList,
  setToDoList,
  toDo,
  inProgres,
  done,
  deletePost,
  setTaskToEdit,
}) {
  const [{ isOver }, drop] = useDrop(() => ({
    accept: "task",
    drop: (item) => addItemToSection(item.id),
    collect: (monitor) => ({
      isOver: !!monitor.isOver(),
    }),
  }));

  let title = "To do";
  let taskToMap = toDo;

  if (status === "InProgress") {
    title = "In progress";
    taskToMap = inProgres;
  }
  if (status === "done") {
    title = "Done";
    taskToMap = done;
  }

  const addItemToSection = (id) => {
    setToDoList((prev) => {
      const mTasks = prev.map((t) => {
        if (t.id === id) {
          return { ...t, status: status };
        }
        return t;
      });
      return mTasks;
    });
  };

  return (
    <div ref={drop} className="Section">
      <div className="headerSection">
        <h2 className="headerSectionTitle">{title}</h2>
        <p className="count">{taskToMap.length}</p>
      </div>
      {taskToMap.length > 0 &&
        taskToMap.map((task) => (
          <Cards
            deletePost={deletePost}
            key={task.id}
            task={task}
            toDoList={toDoList}
            setToDoList={setToDoList}
            onEdit={setTaskToEdit}
          />
        ))}
    </div>
  );
}
